import java.util.*;class A{static Map<Integer,List<Integer>>g=new HashMap<>();static Map<Integer,Integer>m=new HashMap<>();static int f(int u){if(m.containsKey(u))return m.get(u);int r=0;for(int v:g.getOrDefault(u,List.of()))r=Math.max(r,f(v));m.put(u,r+1);return r+1;}public static void main(String[]a){var s=new Scanner(System.in);int n=s.nextInt();var P=new HashSet<Integer>();for(;n-->0;){int x=s.nextInt(),y=s.nextInt();g.computeIfAbsent(x,k->new ArrayList<>()).add(y);P.add(x);P.add(y);}int r=0;for(int u:P)r=Math.max(r,f(u));System.out.println(r);}}